/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    /* ----------------------------------------------------------
       1. Zero the output vector y.
       ---------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) y[j] = 0.0;

    /* ----------------------------------------------------------
       2. Compute tmp = A * x and accumulate Aᵀ * tmp into y.
       ---------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double dot = 0.0;
        const double* Arow = A[i].data();
        for (int j = 0; j < n; ++j) dot += Arow[j] * x[j];
        tmp[i] = dot;

        /* accumulate the i‑th column of Aᵀ into y */
        for (int j = 0; j < n; ++j) {
            y[j] += Arow[j] * dot;
        }
    }
}
