        // Accumulate alpha * A[i][k] * B[k][j]
        for (int k = 0; k < nk; ++k) {
            double aik = alpha * rowA[k];
            const double* rowB = B[k].data();
            for (int j = 0; j < nj; ++j) {
                rowC[j] += aik * rowB[j];
            }
        }
    }
