void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    /* Use raw pointers to the underlying row data for the fastest access.
       The outer loops are parallelised over the rows of C.  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* Ci = C[i].data();              // row i of C
        const double* Ai = A[i].data();        // row i of A

        /* Scale the lower‑triangular part of C first */
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }

        /* Accumulate the rank‑m outer‑product contributions */
        for (int k = 0; k < m; ++k) {
            double aik = Ai[k];
            for (int j = 0; j <= i; ++j) {
                Ci[j] += alpha * aik * A[j][k];
            }
        }
    }
