/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* The original algorithm is:
        B[i][j] = alpha * sum_{k=i+1}^{m-1} A[k][i] * B[k][j]
       for all i=0..m-1 and j=0..n-1.
     *
     * To preserve the exact semantics while improving performance we:
     *   – parallelise the outer loop over rows of B using OpenMP.
     *   – use a local accumulator to reduce the number of loads/stores.
     *   – keep the data access pattern unchanged
     *     (A[k][i] and B[k][j]) so that the harness expectations are met.
     */

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            for (int k = i + 1; k < m; ++k) {
                sum += A[k][i] * B[k][j];
            }
            B[i][j] = alpha * (B[i][j] + sum);
        }
    }
}
