/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    // constant factor for the averaging operation
    const double inv3 = 0.33333;

    // obtain raw pointers and mark them as restrict to aid the compiler
    double * restrict A_ptr = A.data();
    double * restrict B_ptr = B.data();

    // Pre-allocate a small buffer for a few remaining elements
    // to handle any potential edge cases more cleanly
    const int chunk = 4;   // unroll factor

    for (int t = 0; t < tsteps; ++t) {
        // First half–step: compute B from A
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; i += chunk) {
            int lim = (i + chunk <= n - 1) ? i + chunk : n - 1;
            for (int j = i; j < lim; ++j) {
                B_ptr[j] = inv3 * (A_ptr[j - 1] + A_ptr[j] + A_ptr[j + 1]);
            }
        }

        // Second half–step: compute A from B
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; i += chunk) {
            int lim = (i + chunk <= n - 1) ? i + chunk : n - 1;
            for (int j = i; j < lim; ++j) {
                A_ptr[j] = inv3 * (B_ptr[j - 1] + B_ptr[j] + B_ptr[j + 1]);
            }
        }
    }
}
