/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    // Local pointers to the row data for fast indexed access.
    std::vector<double*> row(n);
    for (int i = 0; i < n; ++i) row[i] = L[i].data();

    // Forward substitution
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        double* Li = row[i];
        double* xi = &x[i];
        double* bi = &b[i];

        // Unroll inner loop to reduce branch overhead.
        int j = 0;
        for (; j + 7 < i; j += 8) {
            sum += Li[j  ] * x[j  ];
            sum += Li[j+1] * x[j+1];
            sum += Li[j+2] * x[j+2];
            sum += Li[j+3] * x[j+3];
            sum += Li[j+4] * x[j+4];
            sum += Li[j+5] * x[j+5];
            sum += Li[j+6] * x[j+6];
            sum += Li[j+7] * x[j+7];
        }
        for (; j < i; ++j) sum += Li[j] * x[j];

        *xi = (*bi - sum) / Li[i];
    }
