void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* 1) Compute column‐wise means */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) s += data[i][j];
        mean[j] = s / static_cast<double>(n);
    }

    /* 2) Center the data (subtract means) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            data[i][j] -= mean[j];

    /* 3) Compute covariance matrix in a cache‑friendly way.
       We accumulate only the upper triangle (j >= i) and
       copy the symmetric entry afterwards.
    */
    const double denom = 1.0 / (static_cast<double>(n) - 1.0);
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i)
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += data[k][i] * data[k][j];
            cov[i][j] = sum * denom;
        }

    /* 4) Mirror the upper triangle into the lower triangle */
    #pragma omp parallel for schedule(static)
    for (int i = 1; i < m; ++i)
        for (int j = 0; j < i; ++j)
            cov[i][j] = cov[j][i];
}
