#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y) {

    /* Parallelise the outer loop.  Because each iteration writes only
       to its own row of tmp and y, the iterations are independent.  */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *ai = A[i].data();   /* row of A      */
        double *bi = B[i].data();   /* row of B      */
        double *tmpi = &tmp[i];
        double *yi   = &y[i];
        const double *xi = x.data();

        double sum_tmp = 0.0;
        double sum_y   = 0.0;

        /* Inner loop – unrolled for a little extra vectorisation hint. */
        int j = 0;
        #pragma unroll 4
        for (; j <= n-4; j += 4) {
            sum_tmp += ai[j]   * xi[j];
            sum_tmp += ai[j+1] * xi[j+1];
            sum_tmp += ai[j+2] * xi[j+2];
            sum_tmp += ai[j+3] * xi[j+3];

            sum_y   += bi[j]   * xi[j];
            sum_y   += bi[j+1] * xi[j+1];
            sum_y   += bi[j+2] * xi[j+2];
            sum_y   += bi[j+3] * xi[j+3];
        }

        for (; j < n; ++j) {
            sum_tmp += ai[j] * xi[j];
            sum_y   += bi[j] * xi[j];
        }

        *tmpi = sum_tmp;
        *yi   = alpha * sum_tmp + beta * sum_y;
    }
}
