/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // Flattened pointers for faster indexing
    const double *Aflat = &A[0][0];
    const double *Bflat = &B[0][0];
          double *Cflat = &C[0][0];

    const std::size_t A_row_stride = m;    // A is m x m
    const std::size_t B_row_stride = n;    // B is m x n
    const std::size_t C_row_stride = n;    // C is m x n

    // Parallelise over the outermost dimension (rows of C)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        const double *Ai   = Aflat + i * A_row_stride;
        const double *Bi   = Bflat + i * B_row_stride;
        double *Ci         = Cflat + i * C_row_stride;
        double Aii         = Ai[i];          // A[i][i]

        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            double Bij   = Bi[j];

            // Accumulate over k = 0 .. i-1
            for (int k = 0; k < i; ++k) {
                double Aik = Ai[k];               // A[i][k]
                Ci[j] += alpha * Bij * Aik;
                temp2 += Bflat[k * B_row_stride + j] * Aik;
            }

            // Final update of C[i][j]
            Ci[j] = beta * Ci[j] + alpha * Bij * Aii + alpha * temp2;
        }
    }
}
