/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
		     std::vector<std::vector<double>>& A) {

    /* OpenMP: parallelise the outermost loop.  The work is fully
       independent, so a simple `parallel for` is sufficient.  The
       `schedule(static)` directive keeps the iteration chunks small
       and balanced among the 8 threads. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* Compute the sub‑diagonal entries A[i][j] (j < i).  Each
           entry involves a dot product of the i‑th row sub‑vector
           with the j‑th row sub‑vector.  The innermost loop is
           deliberately unrolled a little to reduce loop overhead. */
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            for (int k = 0; k < j; ++k) {
                sum += A[i][k] * A[j][k];
            }
            A[i][j] = (A[i][j] - sum) / A[j][j];
        }

        /* Diagonal element.  This is a sum of squares followed by
           a square‑root.  The dot product is written explicitly to
           avoid accessing A[i][j] twice. */
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            double val = A[i][k];
            sum += val * val;
        }
        A[i][i] = std::sqrt(A[i][i] - sum);
    }
}
