#include <vector>
#include <cmath>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;
    const double sqrt_n = std::sqrt(static_cast<double>(n));

    /* ---------- Mean ---------- */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / n;
    }

    /* ---------- Standard deviation ---------- */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mu;
            sum += d * d;
        }
        stddev[j] = std::sqrt(sum / n);
        if (stddev[j] <= eps) stddev[j] = 1.0;
    }

    /* ---------- Normalisation ---------- */
    #pragma omp parallel for
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double v = data[i][j] - mean[j];
            v /= sqrt_n * stddev[j];
            data[i][j] = v;
        }
    }

    /* ---------- Correlation matrix ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
    }

    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;
        }
    }
}
