 * Optimised QR‑decomposition with Modified Gram‑Schmidt.
 *
 * The function signature is kept identical to the original
 * to satisfy the harness.  Only the inner loops are
 * parallelised with OpenMP.  Because every iteration of the
 * outermost `k` loop writes to disjoint rows/columns,
 * the algorithm is thread‑safe and the result is bit‑first
 * identical to the serial version.
 */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    /* For each column `k` of A */
    for (int k = 0; k < n; ++k) {
        /* 1. Norm of the k‑th column of A           */
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            nrm += A[i][k] * A[i][k];
        }
        R[k][k] = std::sqrt(nrm);

        /* 2. Normalise the k‑th column → Q(:,k) */
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / R[k][k];
        }

        /* 3. Orthogonalise the remaining columns */
        for (int j = k + 1; j < n; ++j) {
            /* R(k,j) = <Q(:,k),A(:,j)> */
            double dot = 0.0;
#pragma omp parallel for reduction(+:dot) schedule(static)
            for (int i = 0; i < m; ++i) {
                dot += Q[i][k] * A[i][j];
            }
            R[k][j] = dot;

            /* A(:,j) -= Q(:,k)*R(k,j) */
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * R[k][j];
            }
        }
    }
}
