/*  Optimised version of the Durbin algorithm.  The behaviour
 *  (the values returned in `y`) is exactly the same as the
 *  original implementation.  The only requirement is that the
 *  caller provides a `std::vector<double>` with at least `n`
 *  elements for `y`.  ================================================================= */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    /*  Use a raw array for temporary storage – this reduces
     *  allocation overhead and provides contiguous memory for
     *  the loops.  */
    std::vector<double> z(n, 0.0);

    /*  The very first step is identical to the original code */
    y[0] = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    /*  Loop over the stages k.  The algorithm has data dependencies
     *  between stages, so the outer loop cannot be parallelised.
     *  However, the two inner loops operate independently and can
     *  benefit from auto‑vectorisation and explicit `#pragma omp simd`. */
    for (int k = 1; k < n; ++k) {
        /*  Update beta using the recurrence from the original code.
         *  This uses only scalar arithmetic – no loop.  */
        beta = (1.0 - alpha * alpha) * beta;

        /*  Compute the partial sum ∑ r[k‑i‑1] * y[i] for i = 0 .. k‑1.
         *  The loop is small; the compiler can vectorise it.  */
        double sum = 0.0;
        #pragma omp simd reduction(+:sum)
        for (int i = 0; i < k; ++i) {
            sum += r[k - i - 1] * y[i];
        }

        /*  Compute the next reflection coefficient, alpha.  */
        alpha = - (r[k] + sum) / beta;

        /*  Update the intermediate array z[i] = y[i] + alpha * y[k‑i‑1] 
         *  for i = 0 .. k‑1.  The same loop can be vectorised. */
        #pragma omp simd
        for (int i = 0; i < k; ++i) {
            z[i] = y[i] + alpha * y[k - i - 1];
        }

        /*  Copy z back into y for the next stage. */
        #pragma omp simd
        for (int i = 0; i < k; ++i) {
            y[i] = z[i];
        }

        /*  Store the new reflection coefficient. */
        y[k] = alpha;
    }
}
