void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* --------- 1. LU factorisation ------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* ----- lower triangle (LU division) ----------------------------- */
        for (int j = 0; j < i; ++j) {
            double w = A[i][j];
            for (int k = 0; k < j; ++k)
                w -= A[i][k] * A[k][j];
            A[i][j] = w / A[j][j];
        }

        /* ----- upper triangle (subtraction) ----------------------------- */
        for (int j = i; j < n; ++j) {
            double w = A[i][j];
            for (int k = 0; k < i; ++k)
                w -= A[i][k] * A[k][j];
            A[i][j] = w;
        }
    }

    /* --------- 2. Forward substitution y = L⁻¹ b ---------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        for (int j = 0; j < i; ++j)
            w -= A[i][j] * y[j];
        y[i] = w;            // L[i][i] == 1
    }

    /* --------- 3. Backwards substitution x = U⁻¹ y ------------------- */
    #pragma omp parallel for schedule(static) // reverse order pragma: OK because U is upper‑triangular
    for (int idx = 0; idx < n; ++idx) {
        int i = n - 1 - idx;      // loop from n-1 downto 0
        double w = y[i];
        for (int j = i + 1; j < n; ++j)
            w -= A[i][j] * x[j];
        x[i] = w / A[i][i];
    }
}
