                    std::vector<std::vector<std::vector<double>>>& B)
{
    // Flatten the 3‑D containers into a linear array to minimize
    // indexing overhead and improve cache behaviour.
    const size_t N3 = static_cast<size_t>(n) * n * n;
    std::vector<double> flatA(N3), flatB(N3);

    // Helper to compute linear index.
    auto idx = [](int i, int j, int k, int n) noexcept {
        return static_cast<size_t>(i) * n * n + static_cast<size_t>(j) * n + static_cast<size_t>(k);
    };

    // Copy initial data into flat arrays.
#pragma omp parallel for collapse(3) schedule(static)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            for (int k = 0; k < n; ++k)
                flatA[idx(i,j,k,n)] = A[i][j][k];

    const double coef = 0.125;   // 1/8

    for (int t = 1; t <= tsteps; ++t)
    {
        // Compute B from A
#pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
            for (int j = 1; j < n - 1; ++j)
                for (int k = 1; k < n - 1; ++k)
                {
                    size_t id = idx(i,j,k,n);
                    double centre = flatA[id];
                    double val = coef * (flatA[idx(i+1,j,k,n)] - 2.0 * centre +
                                         flatA[idx(i-1,j,k,n)])
