 * overhead.  The logic of the original implementation is preserved,
 * but we use a one–dimensional array for the DP table and compute
 * row‑by‑row with a local accumulator for the k‑loop.  This layout
 * gives the compiler better opportunities for SIMD and cache reuse.
 *
 * The outer two loops are kept sequential because of data dependencies,
 * but the innermost k‑loop is parallelised using OpenMP (static
 * scheduling).  The match test is inlined as a small lambda.
 */

inline int match_int(int b1, int b2) noexcept
{
    return (b1 + b2 == 3) ? 1 : 0;
}

void kernel_nussinov(int n, const std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    // 1‑D view of the 2‑D table: index = i * n + j
    const std::size_t nn = static_cast<std::size_t>(n);
    std::vector<int> view(nn * nn);
    const std::size_t stride = nn;

    // copy table into view (use move if possible)
    for (int i = 0; i < n; ++i)
        std::copy(table[i].begin(), table[i].end(), view.data() + i * nn);

    for (int i = n - 1; i >= 0; --i)
    {
        const std::size_t ioff = static_cast<std::size_t>(i) * stride;
        for (int j = i + 1; j < n; ++j)
        {
            std::size_t idx = ioff + static_cast<std::size_t>(j);
            int best = 0;                         // local accumulator

            // Inherited values
            if (j - 1 >= 0)
                best = std::max(best, view[idx - 1]);
            if (i + 1 < n)
                best = std::max(best, view[ioff + stride]);

            // Base pairing
            if (j - 1 >= 0 && i + 1 < n)
            {
                if (i < j - 1)
                    best = std::max(best, view[idx + stride] + match_int(seq[i], seq[j]));
                else
                    best = std::max(best, view[idx + stride]);
            }

            // Partitioning
#pragma omp parallel for schedule(static)
            for (int k = i + 1; k < j; ++k)
            {
                int val = view[ioff + static_cast<std::size_t>(k)]
                          + view[(static_cast<std::size_t>(k) + 1) * stride + j];
                #pragma omp atomic
                if (val > best) best = val;
            }

            view[idx] = best;
        }
    }

    // copy back to the 2‑D table
    for (int i = 0; i < n; ++i)
        std::copy(view.data() + i * nn, view.data() + (i + 1) * nn,
                  table[i].begin());
