        std::copy(ey_flat.begin() + idx(i, 0, ny), ey_flat.begin() + idx(i + 1, 0, ny), ey[i].begin());

    for (int i = 0; i < nx; ++i)
        std::copy(hz_flat.begin() + idx(i, 0, ny), hz_flat.begin() + idx(i + 1, 0, ny), hz[i].begin());
}
