#include <cmath>
#include <vector>
#include <omp.h>

/* Optimised kernel_deriche preserving exact behaviour. */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    // Pre‑compute constants in float precision
    const float a = static_cast<float>(alpha);
    const float exp_a   = std::expf(-a);
    const float exp_2a  = exp_a * exp_a;
    const float denom   = 1.0f + 2.0f * a * exp_a - exp_2a;
    const float k       = 1.0f - exp_a * (1.0f - exp_a) / denom;

    const float a1 = k, a5 = k;
    const float a2 = k * exp_a * (a - 1.0f), a6 = a2;
    const float a3 = k * exp_a * (a + 1.0f), a7 = a3;
    const float a4 = -k * exp_2a,  a8 = a4;

    const float b1 = std::powf(2.0f, -a),  b2 = -exp_2a;
    const float c1 = 1.0f, c2 = 1.0f;

    /* 1. Forward pass on rows into y1 */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const float in = imgIn[i][j];
            float y = a1 * in + a2 * xm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            xm1 = in;  ym2 = ym1;  ym1 = y;
        }
    }

    /* 2. Backward pass on rows into y2 */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h-1; j >= 0; --j) {
            const float inp = imgIn[i][j];
            float y = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            xp2 = xp1;  xp1 = inp;  yp2 = yp1;  yp1 = y;
        }
    }

    /* 3. Combine into imgOut */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);

    /* 4. Forward pass on columns into y1 */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float out = imgOut[i][j];
            float y = a5 * out + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            tm1 = out;  ym2 = ym1;  ym1 = y;
        }
    }

    /* 5. Backward pass on columns into y2 */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            const float out = imgOut[i][j];
            float y = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            tp2 = tp1;  tp1 = out;  yp2 = yp1;  yp1 = y;
        }
    }

    /* 6. Final combine */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
}
