/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 */

void kernel_adi(
    int tsteps,
    int n,
    std::vector<std::vector<double>>& u,
    std::vector<std::vector<double>>& v,
    std::vector<std::vector<double>>& p,
    std::vector<std::vector<double>>& q
) {
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;

    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);

    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    /* The outer `t` loop cannot be parallelised due to data
       dependencies.  All inner loops are kept as plain scalar
       loops with pointer arithmetic to maximise cache reuse. */
    for (int t = 1; t <= tsteps; ++t) {

        /* ------------------------------------------------------------------
           First sweep (vertical pass)
           ------------------------------------------------------------------*/
        for (int i = 1; i < n - 1; ++i) {
            double* u_curr  = u[i].data();
            double* u_prev  = u[i - 1].data();
            double* u_next  = u[i + 1].data();

            double* v_curr  = v[i].data();
            double* v_next  = v[n - 1].data();            // only v[n-1] used at the end
            double* p_curr  = p[i].data();
            double* q_curr  = q[i].data();

            /* Set first‑column boundary values */
            v_curr[0] = 1.0;
            p_curr[0] = 0.0;
            q_curr[0] = v_curr[0];

            /* Forward recurrence (j = 1 .. n-2) */
            for (int j = 1; j < n - 1; ++j) {
                const double denom = a * p_curr[j - 1] + b;
                p_curr[j] = -c / denom;

                const double num = (-d * u_prev[j - 1]
                                 + (1.0 + 2.0 * d) * u_curr[j - 1]
                                 - f * u_next[j - 1]
                                 - a * q_curr[j - 1]) / denom;
                q_curr[j] = num;
            }

            /* Last‑row boundary value */
            v_curr[n - 1] = 1.0;

            /* Backward sweep (j = n-2 .. 1) */
            for (int j = n - 2; j >= 1; --j)
                v_curr[j] = p_curr[j] * v_curr[j + 1] + q_curr[j];
        }

        /* ------------------------------------------------------------------
           Second sweep (horizontal pass)
           ------------------------------------------------------------------*/
        for (int i = 1; i < n - 1; ++i) {
            double* u_curr  = u[i].data();
            double* u_next  = u[i + 1].data();

            double* v_curr  = v[i].data();
            double* v_prev  = v[i - 1].data();
            double* v_next  = v[i + 1].data();

            double* p_curr  = p[i].data();
            double* q_curr  = q[i].data();

            /* Set first‑row boundary values */
            u_curr[0] = 1.0;
            p_curr[0] = 0.0;
            q_curr[0] = u_curr[0];

            /* Forward recurrence (j = 1 .. n-2) */
            for (int j = 1; j < n - 1; ++j) {
                const double denom = d * p_curr[j - 1] + e;
                p_curr[j] = -f / denom;

                const double num = (-a * v_prev[j]
                                 + (1.0 + 2.0 * a) * v_curr[j]
                                 - c * v_next[j]
                                 - d * q_curr[j - 1]) / denom;
                q_curr[j] = num;
            }

            /* Last‑column boundary value */
            u_curr[n - 1] = 1.0;

            /* Backward sweep (j = n-2 .. 1) */
            for (int j = n - 2; j >= 1; --j)
                u_curr[j] = p_curr[j] * u_curr[j + 1] + q_curr[j];
        }
    }
}
